import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

interface AnimalDetail extends Animal {
  peso_nacimiento: number;
  madre_id: number;
  padre_id: number;
  raza_id: number;
  ubicacion_actual_id: number;
  observaciones: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [filteredAnimals, setFilteredAnimals] = useState<Animal[]>([]);
  const [razas, setRazas] = useState<any[]>([]);
  const [ubicaciones, setUbicaciones] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [showDetail, setShowDetail] = useState<number | null>(null);
  const [animalDetail, setAnimalDetail] = useState<AnimalDetail | null>(null);
  const [filters, setFilters] = useState({
    categoria: '',
    sexo: '',
    estado: '',
    raza: '',
    ubicacion: '',
    busqueda: ''
  });
  const [formData, setFormData] = useState({
    identificador_unico: '',
    nombre: '',
    sexo: 'hembra',
    categoria: 'lechon',
    raza_id: '',
    fecha_nacimiento: '',
    peso_nacimiento: '',
    madre_id: '',
    padre_id: '',
    ubicacion_actual_id: '',
    observaciones: ''
  });

  useEffect(() => {
    loadAnimals();
    loadRazas();
    loadUbicaciones();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
      setFilteredAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    } finally {
      setLoading(false);
    }
  };

  const applyFilters = () => {
    let filtered = animals;

    if (filters.categoria) {
      filtered = filtered.filter(a => a.categoria === filters.categoria);
    }
    if (filters.sexo) {
      filtered = filtered.filter(a => a.sexo === filters.sexo);
    }
    if (filters.estado) {
      filtered = filtered.filter(a => a.estado === filters.estado);
    }
    if (filters.raza) {
      filtered = filtered.filter(a => a.raza_nombre === filters.raza);
    }
    if (filters.ubicacion) {
      filtered = filtered.filter(a => a.ubicacion_nombre === filters.ubicacion);
    }
    if (filters.busqueda) {
      const search = filters.busqueda.toLowerCase();
      filtered = filtered.filter(a => 
        a.identificador_unico.toLowerCase().includes(search) ||
        (a.nombre && a.nombre.toLowerCase().includes(search))
      );
    }

    setFilteredAnimals(filtered);
  };

  useEffect(() => {
    applyFilters();
  }, [filters, animals]);

  const clearFilters = () => {
    setFilters({
      categoria: '',
      sexo: '',
      estado: '',
      raza: '',
      ubicacion: '',
      busqueda: ''
    });
  };

  const getStats = () => {
    const total = animals.length;
    const activos = animals.filter(a => a.estado === 'activo').length;
    const machos = animals.filter(a => a.sexo === 'macho').length;
    const hembras = animals.filter(a => a.sexo === 'hembra').length;
    const reproductores = animals.filter(a => a.categoria === 'reproductor').length;
    const lechones = animals.filter(a => a.categoria === 'lechon').length;

    return { total, activos, machos, hembras, reproductores, lechones };
  };

  const stats = getStats();

  const loadRazas = async () => {
    try {
      const response = await api.get('/animals/razas');
      setRazas(response.data);
    } catch (error) {
      console.error('Error cargando razas:', error);
    }
  };

  const loadUbicaciones = async () => {
    try {
      const response = await api.get('/locations');
      setUbicaciones(response.data.filter((u: any) => u.tipo === 'corral'));
    } catch (error) {
      console.error('Error cargando ubicaciones:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      if (editingId) {
        await api.put(`/animals/${editingId}`, formData);
        alert('Animal actualizado correctamente');
      } else {
        await api.post('/animals', formData);
        alert('Animal registrado exitosamente');
      }
      resetForm();
      loadAnimals();
    } catch (error) {
      console.error('Error guardando animal:', error);
      alert('Error guardando animal');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({
      identificador_unico: '',
      nombre: '',
      sexo: 'hembra',
      categoria: 'lechon',
      raza_id: '',
      fecha_nacimiento: '',
      peso_nacimiento: '',
      madre_id: '',
      padre_id: '',
      ubicacion_actual_id: '',
      observaciones: ''
    });
  };

  const handleEdit = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      const animal = response.data;
      setFormData({
        identificador_unico: animal.identificador_unico,
        nombre: animal.nombre || '',
        sexo: animal.sexo,
        categoria: animal.categoria,
        raza_id: animal.raza_id?.toString() || '',
        fecha_nacimiento: animal.fecha_nacimiento || '',
        peso_nacimiento: animal.peso_nacimiento?.toString() || '',
        madre_id: animal.madre_id?.toString() || '',
        padre_id: animal.padre_id?.toString() || '',
        ubicacion_actual_id: animal.ubicacion_actual_id?.toString() || '',
        observaciones: animal.observaciones || ''
      });
      setEditingId(id);
      setShowForm(true);
    } catch (error) {
      console.error('Error cargando animal:', error);
    }
  };

  const handleView = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      setAnimalDetail(response.data);
      setShowDetail(id);
    } catch (error) {
      console.error('Error cargando detalles:', error);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este animal?')) {
      try {
        await api.delete(`/animals/${id}`);
        alert('Animal eliminado correctamente');
        loadAnimals();
      } catch (error) {
        console.error('Error eliminando animal:', error);
        alert('Error eliminando animal');
      }
    }
  };

  if (loading) return (
    <div className="loading">
      <div className="loading-spinner"></div>
      <p>Cargando animales...</p>
    </div>
  );

  return (
    <div className="fade-in">
      <div className="card-header">
        <div>
          <h1 className="card-title">🐷 Gestión de Animales</h1>
          <p style={{ color: '#7f8c8d', margin: 0 }}>Control completo del inventario animal</p>
        </div>
        <button 
          className="btn btn-primary"
          onClick={() => {
            if (showForm) {
              resetForm();
            } else {
              setShowForm(true);
            }
          }}
        >
          {showForm ? '❌ Cancelar' : '➕ Nuevo Animal'}
        </button>
      </div>

      {/* Estadísticas Rápidas */}
      <div className="grid grid-6 mb-4">
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #3498db, #2980b9)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.total}</div>
          <div style={{ opacity: 0.9 }}>Total</div>
        </div>
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #27ae60, #229954)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.activos}</div>
          <div style={{ opacity: 0.9 }}>Activos</div>
        </div>
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #2196f3, #1976d2)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.machos}</div>
          <div style={{ opacity: 0.9 }}>Machos</div>
        </div>
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #e91e63, #c2185b)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.hembras}</div>
          <div style={{ opacity: 0.9 }}>Hembras</div>
        </div>
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #ff9800, #f57c00)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.reproductores}</div>
          <div style={{ opacity: 0.9 }}>Reproductores</div>
        </div>
        <div className="card text-center" style={{ background: 'linear-gradient(135deg, #9c27b0, #7b1fa2)', color: 'white' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{stats.lechones}</div>
          <div style={{ opacity: 0.9 }}>Lechones</div>
        </div>
      </div>

      {/* Filtros Avanzados */}
      <div className="card mb-4">
        <div className="card-header">
          <h3 className="card-title">🔍 Filtros de Búsqueda</h3>
          <button className="btn btn-secondary btn-sm" onClick={clearFilters}>
            🗑️ Limpiar Filtros
          </button>
        </div>
        <div className="grid grid-3">
          <div className="form-group">
            <label>Búsqueda:</label>
            <input
              type="text"
              className="form-control"
              placeholder="ID o nombre del animal"
              value={filters.busqueda}
              onChange={(e) => setFilters({...filters, busqueda: e.target.value})}
            />
          </div>
          <div className="form-group">
            <label>Categoría:</label>
            <select
              className="form-control"
              value={filters.categoria}
              onChange={(e) => setFilters({...filters, categoria: e.target.value})}
            >
              <option value="">Todas las categorías</option>
              <option value="lechon">Lechón</option>
              <option value="recria">Recría</option>
              <option value="desarrollo">Desarrollo</option>
              <option value="engorde">Engorde</option>
              <option value="reproductor">Reproductor</option>
            </select>
          </div>
          <div className="form-group">
            <label>Sexo:</label>
            <select
              className="form-control"
              value={filters.sexo}
              onChange={(e) => setFilters({...filters, sexo: e.target.value})}
            >
              <option value="">Ambos sexos</option>
              <option value="macho">Macho</option>
              <option value="hembra">Hembra</option>
            </select>
          </div>
          <div className="form-group">
            <label>Estado:</label>
            <select
              className="form-control"
              value={filters.estado}
              onChange={(e) => setFilters({...filters, estado: e.target.value})}
            >
              <option value="">Todos los estados</option>
              <option value="activo">Activo</option>
              <option value="vendido">Vendido</option>
              <option value="muerto">Muerto</option>
            </select>
          </div>
          <div className="form-group">
            <label>Raza:</label>
            <select
              className="form-control"
              value={filters.raza}
              onChange={(e) => setFilters({...filters, raza: e.target.value})}
            >
              <option value="">Todas las razas</option>
              {Array.from(new Set(animals.map(a => a.raza_nombre).filter(Boolean))).map(raza => (
                <option key={raza} value={raza}>{raza}</option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label>Ubicación:</label>
            <select
              className="form-control"
              value={filters.ubicacion}
              onChange={(e) => setFilters({...filters, ubicacion: e.target.value})}
            >
              <option value="">Todas las ubicaciones</option>
              {Array.from(new Set(animals.map(a => a.ubicacion_nombre).filter(Boolean))).map(ubicacion => (
                <option key={ubicacion} value={ubicacion}>{ubicacion}</option>
              ))}
            </select>
          </div>
        </div>
        <div style={{ marginTop: '10px', color: '#7f8c8d', fontSize: '14px' }}>
          Mostrando {filteredAnimals.length} de {animals.length} animales
        </div>
      </div>

      {showForm && (
        <div className="card mb-4 fade-in">
          <div className="card-header">
            <h3 className="card-title">
              {editingId ? '✏️ Editar Animal' : '➕ Registrar Nuevo Animal'}
            </h3>
          </div>
          <form onSubmit={handleSubmit}>
            <div className="grid grid-2">
              <div className="form-group">
                <label>Identificador Único:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.identificador_unico}
                  onChange={(e) => setFormData({...formData, identificador_unico: e.target.value})}
                  required
                  placeholder="Ej: CER001"
                />
              </div>

              <div className="form-group">
                <label>Nombre:</label>
                <input
                  type="text"
                  className="form-control"
                  value={formData.nombre}
                  onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                  placeholder="Nombre del animal (opcional)"
                />
              </div>

              <div className="form-group">
                <label>Sexo:</label>
                <select
                  className="form-control"
                  value={formData.sexo}
                  onChange={(e) => setFormData({...formData, sexo: e.target.value})}
                >
                  <option value="hembra">Hembra</option>
                  <option value="macho">Macho</option>
                </select>
              </div>

              <div className="form-group">
                <label>Categoría:</label>
                <select
                  className="form-control"
                  value={formData.categoria}
                  onChange={(e) => setFormData({...formData, categoria: e.target.value})}
                >
                  <option value="lechon">Lechón</option>
                  <option value="recria">Recría</option>
                  <option value="desarrollo">Desarrollo</option>
                  <option value="engorde">Engorde</option>
                  <option value="reproductor">Reproductor</option>
                </select>
              </div>

              <div className="form-group">
                <label>Fecha de Nacimiento:</label>
                <input
                  type="date"
                  className="form-control"
                  value={formData.fecha_nacimiento}
                  onChange={(e) => setFormData({...formData, fecha_nacimiento: e.target.value})}
                />
              </div>

              <div className="form-group">
                <label>Raza:</label>
                <select
                  className="form-control"
                  value={formData.raza_id}
                  onChange={(e) => setFormData({...formData, raza_id: e.target.value})}
                >
                  <option value="">Seleccionar raza</option>
                  {razas.map(raza => (
                    <option key={raza.id} value={raza.id}>
                      {raza.nombre}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Peso Nacimiento (kg):</label>
                <input
                  type="number"
                  step="0.1"
                  className="form-control"
                  value={formData.peso_nacimiento}
                  onChange={(e) => setFormData({...formData, peso_nacimiento: e.target.value})}
                  placeholder="1.5"
                />
              </div>

              <div className="form-group">
                <label>Madre:</label>
                <select
                  className="form-control"
                  value={formData.madre_id}
                  onChange={(e) => setFormData({...formData, madre_id: e.target.value})}
                >
                  <option value="">Sin madre registrada</option>
                  {animals.filter(a => a.sexo === 'hembra' && a.categoria === 'reproductor').map(animal => (
                    <option key={animal.id} value={animal.id}>
                      {animal.identificador_unico} - {animal.nombre || 'Sin nombre'}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Padre:</label>
                <select
                  className="form-control"
                  value={formData.padre_id}
                  onChange={(e) => setFormData({...formData, padre_id: e.target.value})}
                >
                  <option value="">Sin padre registrado</option>
                  {animals.filter(a => a.sexo === 'macho' && a.categoria === 'reproductor').map(animal => (
                    <option key={animal.id} value={animal.id}>
                      {animal.identificador_unico} - {animal.nombre || 'Sin nombre'}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Ubicación:</label>
                <select
                  className="form-control"
                  value={formData.ubicacion_actual_id}
                  onChange={(e) => setFormData({...formData, ubicacion_actual_id: e.target.value})}
                >
                  <option value="">Sin ubicación asignada</option>
                  {ubicaciones.map(ubicacion => (
                    <option key={ubicacion.id} value={ubicacion.id}>
                      {ubicacion.nombre}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                <label>Observaciones:</label>
                <textarea
                  className="form-control"
                  rows={3}
                  value={formData.observaciones}
                  onChange={(e) => setFormData({...formData, observaciones: e.target.value})}
                  placeholder="Observaciones adicionales..."
                />
              </div>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button type="submit" className="btn btn-success">
                {editingId ? '💾 Actualizar' : '💾 Guardar'} Animal
              </button>
              <button type="button" className="btn btn-secondary" onClick={resetForm}>
                ❌ Cancelar
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="card">
        <div className="card-header">
          <h3 className="card-title">📋 Lista de Animales ({animals.length})</h3>
          <div className="badge badge-info">{filteredAnimals.length} registros</div>
        </div>
        {filteredAnimals.length > 0 ? (
          <div className="table-container">
            <table className="table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Nombre</th>
                <th>Sexo</th>
                <th>Categoría</th>
                <th>Estado</th>
                <th>Raza</th>
                <th>Ubicación</th>
                <th>Nacimiento</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {filteredAnimals.map(animal => (
                <tr key={animal.id}>
                  <td>{animal.identificador_unico}</td>
                  <td>{animal.nombre || '-'}</td>
                  <td>
                    <span className="badge" style={{
                      backgroundColor: animal.sexo === 'hembra' ? '#e91e63' : '#2196f3',
                      color: 'white'
                    }}>
                      {animal.sexo === 'hembra' ? '♀ Hembra' : '♂ Macho'}
                    </span>
                  </td>
                  <td>
                    <span className="badge badge-info" style={{ textTransform: 'capitalize' }}>
                      {animal.categoria}
                    </span>
                  </td>
                  <td>
                    <span className={`badge ${
                      animal.estado === 'activo' ? 'badge-success' : 
                      animal.estado === 'vendido' ? 'badge-warning' : 'badge-danger'
                    }`}>
                      {animal.estado === 'activo' ? '✅ Activo' : 
                       animal.estado === 'vendido' ? '💰 Vendido' : '❌ ' + animal.estado}
                    </span>
                  </td>
                  <td>{animal.raza_nombre || '-'}</td>
                  <td>{animal.ubicacion_nombre || '-'}</td>
                  <td>{animal.fecha_nacimiento ? new Date(animal.fecha_nacimiento).toLocaleDateString() : '-'}</td>
                  <td>
                    <div className="action-buttons">
                      <button 
                        className="btn btn-info btn-sm"
                        onClick={() => handleView(animal.id)}
                        title="Ver detalles"
                      >
                        👁️
                      </button>
                      <button 
                        className="btn btn-warning btn-sm"
                        onClick={() => handleEdit(animal.id)}
                        title="Editar"
                      >
                        ✏️
                      </button>
                      <button 
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDelete(animal.id)}
                        title="Eliminar"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state">
            <div className="empty-state-icon">🐷</div>
            <h3>No hay animales registrados</h3>
            <p>Comienza registrando tu primer animal en el sistema</p>
            <button className="btn btn-primary" onClick={() => setShowForm(true)}>
              ➕ Registrar Primer Animal
            </button>
          </div>
        )}
      </div>

      {/* Modal de detalles */}
      {showDetail && animalDetail && (
        <div className="modal-overlay">
          <div className="card modal-content">
            <div className="card-header">
              <h3 className="card-title">🐷 Detalles del Animal</h3>
              <button 
                className="btn btn-secondary btn-sm"
                onClick={() => setShowDetail(null)}
              >
                ❌
              </button>
            </div>
            <div className="grid grid-2">
              <div>
                <strong>ID:</strong> {animalDetail.identificador_unico}
              </div>
              <div>
                <strong>Nombre:</strong> {animalDetail.nombre || 'Sin nombre'}
              </div>
              <div>
                <strong>Sexo:</strong> {animalDetail.sexo}
              </div>
              <div>
                <strong>Categoría:</strong> {animalDetail.categoria}
              </div>
              <div>
                <strong>Estado:</strong> {animalDetail.estado}
              </div>
              <div>
                <strong>Raza:</strong> {animalDetail.raza_nombre || 'No especificada'}
              </div>
              <div>
                <strong>Fecha Nacimiento:</strong> {animalDetail.fecha_nacimiento ? new Date(animalDetail.fecha_nacimiento).toLocaleDateString() : 'No especificada'}
              </div>
              <div>
                <strong>Peso Nacimiento:</strong> {animalDetail.peso_nacimiento ? `${animalDetail.peso_nacimiento} kg` : 'No registrado'}
              </div>
              <div>
                <strong>Ubicación:</strong> {animalDetail.ubicacion_nombre || 'No asignada'}
              </div>
            </div>
            {animalDetail.observaciones && (
              <div style={{ marginTop: '15px' }}>
                <strong>Observaciones:</strong>
                <p style={{ marginTop: '5px', padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '4px' }}>
                  {animalDetail.observaciones}
                </p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Animals;
